SELECT fatalities
FROM road_safety_data
WHERE year = 2023;

SELECT year
  FROM road_safety_data
  WHERE fatalities = (SELECT MAX(fatalities) FROM road_safety_data);

SELECT SUM(fatalities) AS total_fatalities
FROM road_safety_data
WHERE year = 2020;

SELECT data_id 
FROM road_safety_data 
ORDER BY year, data_id;

SELECT DISTINCT year 
FROM road_safety_data 
ORDER BY year ASC;

SELECT DISTINCT year 
FROM road_safety_data 
ORDER BY year;

SELECT DISTINCT year
FROM road_safety_data
ORDER BY year ASC;

SELECT year, fatalities
FROM road_safety_data
ORDER BY year;

SELECT DISTINCT year
FROM road_safety_data
ORDER BY year ASC;

SELECT AVG(fatality_rate_population) AS avg_fatality_rate
FROM road_safety_data
WHERE year = 2020;
